const report = $json?.report;
const content = report?.content ?? '';
const title = report?.title ?? '';

// Gera prompt para áudio curto (~20s). O Gemini deve responder EXCLUSIVAMENTE com JSON.
const prompt = `Você recebeu um relatório diário em Markdown (Andon/Asana). Crie um roteiro de locução em pt-BR para ~20 segundos (55 a 80 palavras), sem emojis.

Regras:
- Formato: JSON SOMENTE, sem Markdown, sem código-fence.
- JSON com as chaves: audio_script (string).
- audio_script deve ser texto corrido (sem listas), com:
  1) 1 frase de abertura citando o tema do dia (se houver no título);
  2) 3 prioridades principais como frases curtas (inclua responsável quando existir); 
  3) 1 frase final pedindo atenção/ação.
- Não inclua cabeçalhos como "##" ou "#".

TÍTULO: ${title}

RELATÓRIO (Markdown):\n${content}`;

return [{ json: { reportTitle: title, reportContent: content, prompt } }];

const raw = $json?.output ?? $json?.text ?? $json;
const rawStr = typeof raw === 'string' ? raw : JSON.stringify(raw);

// Extrai JSON se vier em algum fence (fallback; ideal é já vir puro).
let jsonStr = rawStr.trim();
const match = jsonStr.match(/```(?:json)?\s*([\s\S]*?)```/i);
if (match) jsonStr = match[1].trim();

let parsed;
try {
  parsed = JSON.parse(jsonStr);
} catch (e) {
  throw new Error(`Falha ao parsear JSON da IA. Saída recebida: ${rawStr.slice(0, 500)}`);
}

if (!parsed?.audio_script || typeof parsed.audio_script !== 'string') {
  throw new Error(`JSON inválido (audio_script ausente). Recebido: ${jsonStr.slice(0, 500)}`);
}

return [{ json: { audio_script: parsed.audio_script.trim() } }];

const BOT_TOKEN = 'REPLACE_TELEGRAM_BOT_TOKEN';
const CHAT_ID = '1069502175';

const audioBase64 = $json?.audio_base64;
if (!audioBase64 || typeof audioBase64 !== 'string') {
  throw new Error(`ElevenLabs: audio_base64 ausente. Chaves recebidas: ${Object.keys($json || {})}`);
}

const audioBuffer = Buffer.from(audioBase64, 'base64');

function buildMultipartFormData({ chatId, audioBuffer, boundary, fileName }) {
  const CRLF = '\r\n';

  const chatPart = Buffer.from(
    `--${boundary}${CRLF}` +
    `Content-Disposition: form-data; name="chat_id"${CRLF}${CRLF}` +
    `${chatId}${CRLF}`
  );

  const audioPartHeader = Buffer.from(
    `--${boundary}${CRLF}` +
    `Content-Disposition: form-data; name="audio"; filename="${fileName}"${CRLF}` +
    `Content-Type: audio/mpeg${CRLF}${CRLF}`
  );

  const audioPartFooter = Buffer.from(`${CRLF}`);
  const endPart = Buffer.from(`--${boundary}--${CRLF}`);

  return Buffer.concat([chatPart, audioPartHeader, audioBuffer, audioPartFooter, endPart]);
}

const boundary = '----n8n-andon-audio-' + Math.random().toString(16).slice(2);
const body = buildMultipartFormData({
  chatId: CHAT_ID,
  audioBuffer,
  boundary,
  fileName: 'andon.mp3',
});

const url = `https://api.telegram.org/bot${BOT_TOKEN}/sendAudio`;

// n8n 2.x task runner: fetch não existe no sandbox — usar helpers.httpRequest
const raw = await this.helpers.httpRequest({
  method: 'POST',
  url,
  headers: {
    'Content-Type': `multipart/form-data; boundary=${boundary}`,
  },
  body,
  json: false,
});

const data = typeof raw === 'string' ? JSON.parse(raw) : raw;
if (!data || data.ok !== true) {
  throw new Error(`Telegram sendAudio falhou: ${JSON.stringify(data).slice(0, 500)}`);
}

return [{ json: { ok: true, telegram: data, chatId: CHAT_ID } }];
